SELECT * FROM saf.tn_saf_batch
WHERE use_end_dt > NOW()
AND oprtr_id = #{oprtrId}
AND batch_id LIKE CONCAT('%', #{batchId}, '%')
AND poc_id_no = #{pocIdNo}
